import os
import re
from typing import Dict, List, Optional

MODALITY_ORDER = ("t1", "t1ce", "t2", "flair")


def detect_modality(path: str) -> Optional[str]:
    name = os.path.basename(path).lower()

    if "t1ce" in name or "t1c" in name:
        return "t1ce"
    if "flair" in name:
        return "flair"
    if re.search(r"(^|[_\-.])t2([_\-.]|$)", name):
        return "t2"
    if re.search(r"(^|[_\-.])t1([_\-.]|$)", name):
        return "t1"

    return None


def order_modality_paths(paths: List[str]) -> List[str]:
    if len(paths) != 4:
        raise ValueError(f"Expected 4 modality files, got {len(paths)}.")

    resolved: Dict[str, str] = {}
    unresolved: List[str] = []
    for path in paths:
        modality = detect_modality(path)
        if modality is None:
            unresolved.append(os.path.basename(path))
            continue
        if modality in resolved:
            raise ValueError(
                f"Duplicate modality detected for '{modality}'. "
                f"Please upload exactly one file for each modality: {', '.join(MODALITY_ORDER)}."
            )
        resolved[modality] = path

    if unresolved:
        raise ValueError(
            "Unable to infer modality from file names: "
            f"{', '.join(unresolved)}. Expected names containing t1, t1ce, t2, flair."
        )

    missing = [modality for modality in MODALITY_ORDER if modality not in resolved]
    if missing:
        raise ValueError(
            f"Missing modality files: {', '.join(missing)}. "
            f"Expected complete set: {', '.join(MODALITY_ORDER)}."
        )

    return [resolved[modality] for modality in MODALITY_ORDER]

import os
import shutil
import uuid
from dataclasses import dataclass
from typing import List, Optional

from werkzeug.datastructures import FileStorage
from werkzeug.utils import secure_filename

from .modality import order_modality_paths


@dataclass(frozen=True)
class TaskContext:
    task_id: str
    upload_dir: str
    output_dir: str
    image_paths: List[str]


class TaskStorageService:
    def __init__(self, upload_root: str, output_root: str):
        self.upload_root = upload_root
        self.output_root = output_root
        os.makedirs(self.upload_root, exist_ok=True)
        os.makedirs(self.output_root, exist_ok=True)

    def create_task(self, files: List[FileStorage]) -> TaskContext:
        if not files:
            raise ValueError("No files part in the request.")
        if len(files) != 4:
            raise ValueError(f"Expected 4 NIfTI modalities, but got {len(files)}.")

        task_id = uuid.uuid4().hex[:8]
        upload_dir = os.path.join(self.upload_root, task_id)
        output_dir = os.path.join(self.output_root, task_id)
        os.makedirs(upload_dir, exist_ok=True)
        os.makedirs(output_dir, exist_ok=True)

        saved_paths: List[str] = []
        try:
            for file in files:
                filename = secure_filename(file.filename or "")
                if not filename:
                    continue

                lower_name = filename.lower()
                if not (lower_name.endswith(".nii") or lower_name.endswith(".nii.gz")):
                    raise ValueError(f"Invalid file type: {filename}. Only .nii or .nii.gz files are supported.")

                file_path = os.path.join(upload_dir, filename)
                file.save(file_path)
                saved_paths.append(file_path)

            if len(saved_paths) != 4:
                raise ValueError("Exactly 4 valid files must be provided.")

            ordered_paths = order_modality_paths(saved_paths)
        except Exception:
            self._cleanup_task_dirs(upload_dir=upload_dir, output_dir=output_dir)
            raise

        return TaskContext(
            task_id=task_id,
            upload_dir=upload_dir,
            output_dir=output_dir,
            image_paths=ordered_paths,
        )

    @staticmethod
    def _cleanup_task_dirs(upload_dir: str, output_dir: str) -> None:
        shutil.rmtree(upload_dir, ignore_errors=True)
        shutil.rmtree(output_dir, ignore_errors=True)

    def resolve_output_file(self, task_id: str, filename: str) -> Optional[str]:
        safe_filename = secure_filename(filename)
        if not safe_filename:
            return None

        file_path = os.path.join(self.output_root, task_id, safe_filename)
        if os.path.exists(file_path):
            return file_path
        return None

import os
import sys

from flask import Flask, jsonify, request, send_file
from flask_cors import CORS

BASE_DIR = os.path.dirname(os.path.abspath(__file__))
PROJECT_ROOT = os.path.dirname(BASE_DIR)

if PROJECT_ROOT not in sys.path:
    sys.path.append(PROJECT_ROOT)

from services.inference_service import SegmentationInferenceService
from services.task_storage import TaskStorageService


def _resolve_weight_path(env_name: str, candidates: list[str]) -> str:
    env_path = os.getenv(env_name)
    if env_path:
        return env_path

    for path in candidates:
        if os.path.exists(path):
            return path

    return candidates[0]


def _resolve_model_weights() -> dict[str, str]:
    unet_candidates = [
        os.path.join(PROJECT_ROOT, "weights", "baseline_unet_best.pth"),
        os.path.join(PROJECT_ROOT, "scripts", "weights", "baseline_unet_best.pth"),
    ]
    mamba_candidates = [
        os.path.join(PROJECT_ROOT, "weights", "mamba_unet_best.pth"),
        os.path.join(PROJECT_ROOT, "scripts", "weights", "mamba_unet_best.pth"),
    ]

    return {
        "unet": _resolve_weight_path("MODEL_UNET_WEIGHTS_PATH", unet_candidates),
        "mamba": _resolve_weight_path("MODEL_MAMBA_WEIGHTS_PATH", mamba_candidates),
    }


def create_app() -> Flask:
    app = Flask(__name__)
    CORS(app)

    upload_root = os.path.join(BASE_DIR, "workspace", "uploads")
    output_root = os.path.join(BASE_DIR, "workspace", "outputs")

    storage = TaskStorageService(upload_root=upload_root, output_root=output_root)
    infer_service = SegmentationInferenceService(model_weights=_resolve_model_weights())

    @app.route("/api/health", methods=["GET"])
    def health_check():
        return jsonify({"status": "running", "service": "Brain Tumor Segmentation API"}), 200

    @app.route("/api/predict", methods=["POST"])
    def predict():
        files = request.files.getlist("files")
        model_name = request.form.get("model", "unet")

        try:
            task = storage.create_task(files)
            _, metrics = infer_service.run(
                image_paths=task.image_paths,
                output_dir=task.output_dir,
                model_name=model_name,
            )
        except ValueError as exc:
            return jsonify({"error": str(exc)}), 400
        except FileNotFoundError as exc:
            return jsonify({"error": str(exc)}), 500
        except Exception as exc:
            return jsonify({"error": f"Inference failed: {exc}"}), 500

        return jsonify(
            {
                "message": "Inference successful",
                "task_id": task.task_id,
                "mask_url": f"/api/download/{task.task_id}/pred_mask.nii.gz",
                "model": model_name,
                "metrics": metrics,
            }
        ), 200

    @app.route("/api/download/<task_id>/<filename>", methods=["GET"])
    def download_file(task_id: str, filename: str):
        file_path = storage.resolve_output_file(task_id=task_id, filename=filename)
        if file_path is None:
            return jsonify({"error": "File not found"}), 404
        return send_file(file_path, as_attachment=True)

    return app


app = create_app()


if __name__ == "__main__":
    debug_enabled = os.getenv("FLASK_DEBUG", "false").lower() == "true"
    app.run(host="0.0.0.0", port=5000, debug=debug_enabled)

import axios from 'axios';

const normalizedBase = (import.meta.env.VITE_API_BASE_URL || '').replace(/\/$/, '');

export const apiClient = axios.create({
  baseURL: normalizedBase || undefined,
});

export const toApiUrl = (path: string): string => {
  if (!path) {
    return path;
  }

  if (/^https?:\/\//i.test(path)) {
    return path;
  }

  const normalizedPath = path.startsWith('/') ? path : `/${path}`;
  if (!normalizedBase) {
    return normalizedPath;
  }

  return `${normalizedBase}${normalizedPath}`;
};

