          target: proxyTarget,
          changeOrigin: true,
        },
      },
    },
  }
})

from services.inference_service import SegmentationInferenceService


def run_medical_inference(patient_dict, weights_path, output_dir, device_str="cpu", model_name="unet"):
    image_paths = patient_dict.get("image", [])
    if not image_paths:
        raise ValueError("patient_dict must contain key 'image' with modality file paths.")

    service = SegmentationInferenceService(model_weights={model_name: weights_path}, default_device=device_str)
    return service.run(image_paths=image_paths, output_dir=output_dir, model_name=model_name, device=device_str)

