import os
from typing import Dict


def resolve_weight_path(env_name: str, candidates: list[str]) -> str:
    env_path = os.getenv(env_name)
    if env_path:
        return env_path

    for path in candidates:
        if os.path.exists(path):
            return path

    return candidates[0]


def resolve_model_weights(project_root: str) -> Dict[str, str]:
    unet_candidates = [
        os.path.join(project_root, "weights", "baseline_unet_best.pth"),
        os.path.join(project_root, "scripts", "weights", "baseline_unet_best.pth"),
    ]
    mamba_candidates = [
        os.path.join(project_root, "weights", "mamba_unet_best.pth"),
        os.path.join(project_root, "scripts", "weights", "mamba_unet_best.pth"),
    ]

    return {
        "unet": resolve_weight_path("MODEL_UNET_WEIGHTS_PATH", unet_candidates),
        "mamba": resolve_weight_path("MODEL_MAMBA_WEIGHTS_PATH", mamba_candidates),
    }

import os
import sys

from fastapi import FastAPI, HTTPException

BASE_DIR = os.path.dirname(os.path.abspath(__file__))
PROJECT_ROOT = os.path.dirname(BASE_DIR)

if PROJECT_ROOT not in sys.path:
    sys.path.append(PROJECT_ROOT)

from api.config import resolve_model_weights
from api.schemas import InferRequest, InferResponse
from services.inference_service import SegmentationInferenceService
from services.modality import order_modality_paths


def create_app() -> FastAPI:
    app = FastAPI(title="FinalDesign Inference Service", version="1.0.0")
    infer_service = SegmentationInferenceService(model_weights=resolve_model_weights(PROJECT_ROOT))

    @app.get("/internal/health")
    def health_check() -> dict[str, str]:
        return {"status": "running", "service": "Brain Tumor Segmentation Inference"}

    @app.post("/internal/infer", response_model=InferResponse)
    def infer(request: InferRequest) -> InferResponse:
        model_name = request.model.strip().lower()

        try:
            ordered_paths = order_modality_paths(request.image_paths)
            output_path, metrics = infer_service.run(
                image_paths=ordered_paths,
                output_dir=request.output_dir,
                model_name=model_name,
            )
        except ValueError as exc:
            raise HTTPException(status_code=400, detail=str(exc)) from exc
        except FileNotFoundError as exc:
            raise HTTPException(status_code=500, detail=str(exc)) from exc
        except Exception as exc:
            raise HTTPException(status_code=500, detail=f"Inference failed: {exc}") from exc

        return InferResponse(
            mask_filename=os.path.basename(output_path),
            model=model_name,
            metrics=metrics,
        )

    return app


app = create_app()

